#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

static at::Tensor conv2d_subtract_tanh_subtract_avg_pool_impl_npu(
    const at::Tensor& x,
    const at::Tensor& weight,
    c10::optional<at::Tensor> bias_opt,
    double subtract1_value,
    double subtract2_value,
    int64_t kernel_size_pool) {

    TORCH_CHECK(x.dim() == 4, \"x must be 4D NCHW\");
    TORCH_CHECK(weight.dim() == 4, \"weight must be 4D OIHW\");
    TORCH_CHECK(x.size(1) == weight.size(1), \"in_channels mismatch\");

    const int64_t N = x.size(0);
    const int64_t C = x.size(1);
    const int64_t H = x.size(2);
    const int64_t W = x.size(3);

    const int64_t O = weight.size(0);
    const int64_t Kh = weight.size(2);
    const int64_t Kw = weight.size(3);

    TORCH_CHECK(H >= Kh && W >= Kw, \"Kernel larger than input\");
    TORCH_CHECK(kernel_size_pool > 0, \"kernel_size_pool must be > 0\");

    const int64_t Ho = H - Kh + 1;
    const int64_t Wo = W - Kw + 1;
    const int64_t Hp = Ho / kernel_size_pool;
    const int64_t Wp = Wo / kernel_size_pool;

    at::Tensor bias;
    if (bias_opt.has_value()) {
        bias = bias_opt.value();
        TORCH_CHECK(bias.numel() == O, \"bias length must equal out_channels\");
    } else {
        bias = at::zeros({O}, weight.options());
    }

    at::Tensor result = at::empty({N, O, Hp, Wp}, x.options());

    EXEC_NPU_CMD(aclnnConv2dSubtractTanhSubtractAvgPoolCustom,
                 x, weight, bias,
                 static_cast<float>(subtract1_value),
                 static_cast<float>(subtract2_value),
                 static_cast<int>(kernel_size_pool),
                 result);
    return result;
}

